import React, { useEffect, useState } from "react"
import { Slide } from "../slide/Slide"
import { SlideIndex } from "./CourseDef"
import { ThemeList } from "./ThemeList"

export type CourseProps = {
    updateState: () => void
}

export type ChooseSlideType = {
    reset: () => void
    set: (themeIndex: number, slideIndex: number) => void
}

export const ChooseSlideContext = React.createContext<ChooseSlideType>({} as ChooseSlideType)

export function Course({ updateState }: CourseProps) {
    const [slideIndex, setSlideIndex] = useState<SlideIndex | null>(null)
    const chooser: ChooseSlideType = {
        reset: function (): void {
            setSlideIndex(null)
        },
        set: function (themeIndex: number, slideIndex: number): void {
            setSlideIndex(new SlideIndex(themeIndex, slideIndex))
        }
    }
    // useEffect(()=>{
    //     setSlideIndex(new SlideIndex(0,1))
    // }, [])

    return <ChooseSlideContext.Provider
        value={chooser}>
        {(slideIndex == null) ?
            <ThemeList></ThemeList> :
            <Slide slideIndex={slideIndex} updateStat={updateState} home={() => setSlideIndex(null)}></Slide>}
    </ChooseSlideContext.Provider>
}