import React, { useEffect, useState } from "react";
import YAML from 'yaml';
import { CONTENT_URL, DB_TABLE, supabase } from "../index";
import { Course } from "./Course";
import { CourseStatDB, CourseState } from "./CourseDef";

export const CourseStateContext = React.createContext<CourseState>({} as CourseState)

export function CourseInit() {
    const [courseState, setCourseState] = useState<CourseState | null>(null)

    const updateState = () => {
        if (courseState != null)
            supabase
                .from(DB_TABLE)
                .select()
                .then(
                    ({ data: stat }) => {
                        if (stat != null) {
                            const state = new CourseState(
                                courseState.data,
                                stat as CourseStatDB[]
                            )
                            // console.log(state)
                            setCourseState(state)
                        }
                    }
                )
    }

    useEffect(() => {
        const dataPromise = fetch(CONTENT_URL + "map.yaml")
            .then((response) => response.text())
        const statPromise = supabase
            .from(DB_TABLE)
            .select()
        Promise.all([dataPromise, statPromise])
            .then(
                ([dataResult, statResult]) => {
                    const { data: stat } = statResult
                    if (stat != null) {
                        const state = new CourseState(
                            YAML.parse(dataResult),
                            stat as CourseStatDB[]
                        )
                        // console.log(state)
                        setCourseState(state)
                    }
                }
            )
    }, [])


    if (courseState == null)
        return <div>Инициализация курса</div>
    else
        return <CourseStateContext.Provider value={courseState} >
            <Course updateState={updateState}></Course>
        </CourseStateContext.Provider>

}


