import { FormEvent, useContext, useState } from 'react'
import { supabase } from '../index'
import { RouterContext } from '../app/Router'
import { SessionContext, SignOffProps } from '../app/App'


export function Auth({ signOff }: SignOffProps) {
  const [loading, setLoading] = useState(false)
  const [email, setEmail] = useState('')
  const router = useContext(RouterContext)
  const session = useContext(SessionContext)

  const handleLogin = async (event: FormEvent) => {
    event.preventDefault()

    setLoading(true)
    const { error } = await supabase.auth.signInWithOtp({ email })

    if (error) {
      alert(error.message)
    } else {
      alert('На электронную почту выслана ссылка для входа')
    }
    setLoading(false)
  }

  const regForm = <form className="form-widget" onSubmit={handleLogin}>
    <div>
      <input
        className="inputField"
        type="email"
        placeholder="Your email"
        value={email}
        required={true}
        onChange={(e) => setEmail(e.target.value)}
      />
    </div>
    <div>
      <button className={'button block'} disabled={loading}>
        {loading ? <span>Загрузка</span> : <span>Выслать ссылку на вход</span>}
      </button>
    </div>
  </form>

  return (<div>
    <div><button onClick={() => router.course()}>К курсу</button></div>
    <div>
      {session
        ? <button onClick={signOff}>Выйти</button>
        : regForm}
    </div>
  </div>)
}