import { useContext } from "react";
import { slideCode2, slideIsDone } from "../slide/tools";
import { CourseStateContext } from "./CourseInit";
import { ChooseSlideContext } from "./Course";

type SlidesProps = {
    themeIndex: number
}

function SlideList({ themeIndex }: SlidesProps) {
    const { data, stat } = useContext(CourseStateContext)
    const slideChooser = useContext(ChooseSlideContext)
    const { url: themeUrl, slides } = data.themes[themeIndex]

    const slidesItem =
        slides.map((sildeData, slideIndex) => {
            const slideCode = slideCode2(themeUrl, sildeData.url)
            const slideStat = stat[slideCode]
            const isDone = (slideStat) ? slideIsDone(sildeData, slideStat) : false
            return <li
                className={isDone ? "slideDone" : ""}
                key={slideIndex}
                onClick={e => slideChooser.set(themeIndex, slideIndex)}>
                {sildeData.title}
            </li>
        })
    return (
        <div>
            <ul>{slidesItem}</ul>
        </div>
    )
}

export default SlideList;