import SlideList from "./SlideList"

type ThemeProps = {
    themeIndex: number
    themeTitle: string
    isOpen: boolean
}

function Theme({themeIndex, themeTitle, isOpen}: ThemeProps){
    return (
        <div>
            <h4>{themeTitle}</h4>
            {isOpen?<SlideList themeIndex={themeIndex}></SlideList>:""}
        </div>
    )
}

export default Theme;