import { SlideData, SlideAnswer } from "../course/CourseDef"


const QUIZ_RATE = 0.6

export function slideCode(url: string): number {
    const list = url.split("/")
    const last = list[list.length - 1]
    // eslint-disable-next-line eqeqeq
    if (last == "") {
        return slideCode2(list[list.length - 3], list[list.length - 2])
    } else {
        return slideCode2(list[list.length - 2], last)
    }
}

export function slideCode2(themeUrl: string, slideUrl: string) {
    return Number(themeUrl.slice(0, 1)) * 100 + Number(slideUrl.slice(0, 1))
}

export function slideIsDone(pages: SlideData, stats: SlideAnswer): boolean {
    if (stats.audio.length < pages.slide)
        return false
    if (stats.quizSuccess.length < pages.quiz * QUIZ_RATE)
        return false
    return true
}

