import { useContext } from "react"
import { SessionContext } from "../app/App"
import { RouterContext } from "../app/Router"
import { SlideAnswer, SlideData } from "../course/CourseDef"
import { slideIsDone } from "./tools"

interface SlideInfoProps {
    slideData: SlideData
    slideStat: SlideAnswer
    pageIsDone: boolean
    home: () => void
    reset: () => void
}

export function SlideInfo({ slideData, slideStat, pageIsDone, reset, home }: SlideInfoProps) {
    const session = useContext(SessionContext)
    const setRoute = useContext(RouterContext)
    if (session)
        return (
            <div>
                <button onClick={() => setRoute.auth()}>{session? session.user.email: "Регистрация"}</button>
                {slideIsDone(slideData, slideStat) ? <span><b>Урок зачтен. </b></span> : ""}
                {pageIsDone ? <span><b> Страница пройдена. </b></span> : ""}
                <button onClick={home}>Домой</button>
                <span> Аудиослайдов: {slideStat.audio.length} из {slideData.slide}.
                    Тестов сданных: {slideStat.quizSuccess.length},
                    не сданных: {slideStat.quizFail.length}  из {slideData.quiz}.&nbsp;
                </span>
                <button onClick={() => confirm(reset)}>Сброс</button>
            </div>
        )
    else
        return (<div>
            <button onClick={() => setRoute.auth()}>Регистрация</button>
            <button onClick={home}>Домой</button>
        </div>)
}

function confirm(reset: () => void) {
    if (window.confirm("Сбросить результаты прохождения всех страниц текущего урока?"))
        reset()
}
