interface SlideEngineProps {
    url: string
}

export  function SlideEngine({url}: SlideEngineProps){
    return (
        <div>
            <div className="reveal" style={{ height: "90vh" }}>
                <div className="slides">
                    <section data-markdown={url + ".md"}
                        data-separator="^----$"
                        data-separator-vertical="^---$" />
                </div>
            </div>
        </div>)
}