import React, { useState } from "react";
import { CourseInit } from "../course/CourseInit";
import { Auth } from "../supabase/Auth";
import { SignOffProps } from "./App";

export type UserMode = "User" | "Guest"
export type Route = "Auth" | "Course"

export class RouterContextType {
    setRoute: (route: Route) => void
    constructor(setRoute: (route: Route) => void = () => { }) {
        this.setRoute = setRoute
    }

    auth() { this.setRoute("Auth") }
    course() { this.setRoute("Course") }
}
export const RouterContext = React.createContext<RouterContextType>(new RouterContextType());


export function Router({ signOff }: SignOffProps) {
    const [route, setRoute] = useState("")
    const context = new RouterContextType((s) => setRoute(s))
    return (
        <RouterContext.Provider
            value={context}>
            {route === "Auth" ?
                <Auth signOff={signOff} /> :
                <CourseInit />}
        </RouterContext.Provider>
    )
}