export type SlideData = {
    url: string
    title: string
    slide: number
    quiz: number
}

export type ThemeData = {
    url: string
    title: string
    slides: SlideData[]
}

export type CourseData = {
    url: string
    title: string
    themes: ThemeData[]
}

export type CourseStatDB = {
    code: number | null
    created_at: string
    page: number
    slide: number
    status: number
    user_id: string
  }

export type PageStatus = number | "PAGE STATUS"
export type PageCode = number 
export type PageResult = number | null

export class PageAnswer {
    status: PageStatus
    result: PageResult
    constructor(status: PageStatus, result: PageResult ) {
        this.status = status
        this.result = result
    }
}


export type SlideCode = number

export class SlideAnswer {
    answers: Record<PageCode, PageAnswer> = []

    addElem(code: PageCode, status: PageStatus, result: PageResult){
        this.answers[code] = new PageAnswer(status, result)
    }
    static statusCode: Record<string, number> = {
        "done": 1,
        "pass": 2,
        "fail": 12
    }
    get audio() {
        return Object.entries(this.answers).filter(([pc, pa]) => pa.status === 1)
    }
    get quizSuccess(){
        return Object.entries(this.answers).filter(([pc, pa]) => pa.status === 2)
    }
    get quizFail(){
        return Object.entries(this.answers).filter(([pc, pa]) => pa.status === 12)
    }
}

export type CourseStat = Record<SlideCode, SlideAnswer>

export class CourseState {
    data: CourseData
    stat: CourseStat
    constructor(data: CourseData, stat: CourseStatDB[]) {
        this.data = data
        this.stat = this.convert(stat)
    }
    convert(statdb: CourseStatDB[]): Record<SlideCode, SlideAnswer> {
        const result: Record<SlideCode, SlideAnswer> = {}
        statdb.forEach(({ slide, page, status, code }) => {
            if (result[slide] == null)
                result[slide] = new SlideAnswer()
            result[slide].addElem(page, status, code)
        })
        return result
    }
}

export class SlideIndex {
    themeIndex: number
    slideIndex: number
    constructor(themeIndex: number, slideIndex: number) {
        this.themeIndex = themeIndex
        this.slideIndex = slideIndex
    }
}

export class PageIndex {
    indexh: number
    indexv: number
    constructor(indexh: number, indexv: number) {
        this.indexh = indexh
        this.indexv = indexv
    }
}

