import { useContext, useState } from "react";
import { CourseStateContext } from "./CourseInit";
import Theme from "./Theme";
import { RouterContext } from "../app/Router";
import { SessionContext } from "../app/App";


export function ThemeList() {
    const { data } = useContext(CourseStateContext)
    const setRoute = useContext(RouterContext)
    const session = useContext(SessionContext)
    const [openTheme, setOpenTheme] = useState(0);

    const themes = data.themes.map(({ title }, index) => {
        return (
            <li key={index} onClick={_ => setOpenTheme(index)}>
                <Theme
                    themeIndex={index}
                    themeTitle={title}
                    isOpen={index === openTheme}
                ></Theme>
            </li>
        )
    });

    return (<div>
        <button onClick={() => setRoute.auth()}>{session ? session.user.email : "Регистрация"}</button>
        <h2>{data.title}</h2>
        <ul>{themes}</ul>
    </div>)
}
