import { useCallback, useContext, useEffect, useRef, useState } from "react";
import { SessionContext } from "../app/App";
import { PageCode, SlideAnswer, SlideIndex } from "../course/CourseDef";
import { CourseStateContext } from "../course/CourseInit";
import { CONTENT_URL, DB_TABLE, supabase } from "../index";
import { SlideEngine } from "./SlideEngine";
import { SlideInfo } from "./SlideInfo";
import { slideCode } from "./tools";

type SlideProps = {
    slideIndex: SlideIndex
    updateStat: () => void
    home: () => void
}

export function Slide({ slideIndex, updateStat, home }: SlideProps) {
    const { data, stat } = useContext(CourseStateContext)
    const session = useContext(SessionContext)
    const [page, setPage] = useState<PageCode>(0)

    const themeData = data.themes[slideIndex.themeIndex]
    const slideData = themeData.slides[slideIndex.slideIndex]
    const url = CONTENT_URL + themeData.url + "/" + slideData.url
    const _slideCode = slideCode(url)
    let slideStat = stat[_slideCode]
    if (slideStat == null)
        slideStat = new SlideAnswer()
    const initCode = "slide_init('" + url + "/')"

    /* eslint no-eval: 0 */
    const deck = useRef<Reveal>();

    const pageDone = useCallback(
        function (page: PageCode, event: string, resultCode?: number) {
            if (session)
                supabase
                    .from(DB_TABLE)
                    .insert({
                        status: SlideAnswer.statusCode[event],
                        slide: _slideCode,
                        page: page,
                        code: resultCode,
                        user_id: session?.user.id
                    })
                    .then(updateStat)
    }, [_slideCode, updateStat, session])

    function reset() {
        supabase
            .from(DB_TABLE)
            .delete()
            .eq("slide", _slideCode)
            .then(() => {
                updateStat()
                document.dispatchEvent(new CustomEvent("resetSlide"))
            })
    }

    useEffect(() => {
        if (deck.current == null) {
            deck.current = eval(initCode)
        }
        (window as any).Courser = {
            "pageIsDone": function (pageCode: PageCode) {
                setPage(pageCode)
                return slideStat.answers[pageCode]
            },
            "pageDone": function (page: PageCode, event: string, resultCode?: number) {
                setPage(page)
                pageDone(page, event, resultCode)
            }
        }
    }, [initCode, slideStat, pageDone, url])



    return (
        <div>
            <SlideInfo slideData={slideData} slideStat={slideStat} pageIsDone={slideStat.answers[page] != null} reset={reset} home={home}></SlideInfo>
            <SlideEngine url={url}></SlideEngine>
        </div>)
}

